function s({motorcyclePrice:t,downPayment:o,months:a,annualInterestRate:c}){const n=Math.max(t-o,0),e=c/12/100;if(n===0||a<=0)return{principal:0,monthlyInterestRate:e,monthlyPayment:0,totalPayable:0};const l=n*e*a,r=n+l,m=r/a;return{principal:n,monthlyInterestRate:e,monthlyPayment:m,totalPayable:r}}function u(t){return{downPayment:t.downPaymentOptions[0]??0,months:t.availableTerms[0]??12,annualInterestRate:12}}function i(t){return new Intl.NumberFormat("en-PH",{style:"currency",currency:"PHP",maximumFractionDigits:0}).format(t)}export{s as e,i as f,u as g};
